INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Workout routine builder$q$, $q$Design weekly training plans from a library of 100-plus exercises with custom sets, reps, weight, duration, or distance targets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Automatic weight progression$q$, $q$Apply progression rules so routines automatically adjust load or volume across training cycles.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Nutrition and calorie tracking$q$, $q$Log meals against the Open Food Facts database of millions of foods with automatic macro and calorie calculation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Body measurement and photo logging$q$, $q$Track body weight, custom measurements, and progress photos over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$REST API$q$, $q$Build custom integrations or automations against wger data using the built-in API.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Basic gym management$q$, $q$Multi-user support lets trainers or small gyms manage several trainees from one instance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Cross-platform apps$q$, $q$Official Android and iOS apps plus F-Droid and Flathub distribution for open-source app stores.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Self-hosted deployment$q$, $q$Deploy via Docker for full control of the server and data, with no ads or data sharing.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Completely free and open source with no feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Full data ownership through self-hosting$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Large exercise and food database for planning and logging$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Active community contributing translations and features$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$REST API enables custom integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Requires self-hosting knowledge or a third-party managed host to get started$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$No official company support channel or SLA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Mobile apps and UI are less polished than some commercial fitness apps$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Advanced gym-business features are more limited than dedicated gym-management software$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Is wger free to use$q$, $q$Yes. wger is free, open-source software licensed under AGPL-3.0, with no paid tiers from the project itself.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Do I need to self-host wger$q$, $q$The core project is self-hosted, typically via Docker, though third-party providers offer managed hosting for a fee if you would rather not run your own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$What can I track in wger$q$, $q$Workout routines and exercise progress, nutrition and calorie intake using the Open Food Facts database, and body weight, measurements, and progress photos.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Does wger have mobile apps$q$, $q$Yes, official Android and iOS apps are available, with the Android build also distributed via F-Droid and Flathub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Can trainers manage multiple clients in wger$q$, $q$Yes, wger includes basic multi-user and gym-management functionality suitable for trainers or small gyms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Is my data private in wger$q$, $q$Since wger is self-hosted, you control where your data lives; the project states it does not use ads or sell personal information.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Does wger have an API$q$, $q$Yes, a REST API is available for building integrations or automations on top of your wger data.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Who maintains wger$q$, $q$wger is maintained by the wger-project open-source community on GitHub, originally started by developer Roland Geider.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Self-hosted personal training log$q$, $q$Individuals who want a private, ad-free alternative to commercial fitness apps can self-host wger to track workouts, nutrition, and body progress.$q$, $q$Fitness enthusiasts and self-hosting hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Small gym or personal trainer client management$q$, $q$Trainers can run a shared wger instance to plan routines and monitor progress for multiple clients.$q$, $q$Independent personal trainers and small gyms$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Developer-extensible fitness platform$q$, $q$Developers can use wger's REST API and open codebase to build custom fitness tools or integrate training data into other systems.$q$, $q$Developers and fitness-tech tinkerers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full access to workout planning","Nutrition tracking with Open Food Facts","Body measurement and photo logging","REST API access","Basic multi-user gym management","Docker-based deployment"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$overview$q$, $q$What Is wger$q$, 2, ARRAY[$q$wger is a free, open-source fitness and workout management platform that lets users plan training routines, track nutrition, and log body progress without relying on a closed, subscription-based app.$q$, $q$The project began as a personal effort by developer Roland Geider and was shared publicly in 2014. It is licensed under AGPL-3.0, meaning the complete source code is open, self-hostable, and modifiable by anyone.$q$, $q$Because there is no company behind wger charging for access, the platform is maintained by an open community of contributors on GitHub, with translations, exercise data, and features added collaboratively over time.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$wger combines workout planning, nutrition tracking, and body-progress logging in one system. Training routines can be built from a library of over 100 exercises with configurable sets, reps, weight, or distance targets, and support automatic weight-progression rules.$q$, $q$Nutrition tracking taps the Open Food Facts database, giving users access to a catalog of millions of foods with automatic calculation of calories, protein, carbs, and fat for logged meals.$q$, $q$Users can log body weight and custom measurements and upload progress photos, while a REST API supports building custom integrations. Basic gym-management and multi-user features make wger usable by trainers managing several clients, not just individuals.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$wger is completely free to use as self-hosted, open-source software; there is no paid tier, license fee, or feature paywall from the project itself.$q$, $q$Most users deploy it via Docker on their own server, VPS, or home lab, giving them full ownership of their fitness and nutrition data with no ads and no data sold to third parties.$q$, $q$For people who do not want to manage their own server, third-party providers offer managed wger hosting for a fee, but this is a separate commercial service layered on top of the free project rather than an official wger pricing plan.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c05a9b7-fdb5-409f-8a14-64eb71fbdace', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$No-code in-app guidance editor$q$, $q$Build task lists, smart tips, flows, beacons, pop-ups, and launchers without writing code, with AI-assisted content authoring.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Simulated training and Mirror$q$, $q$Capture real application workflows and convert them into guided simulations and SCORM-exportable training content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Product analytics$q$, $q$Track user action tags, funnels, trends, and user journeys to identify friction points across applications.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Enterprise content governance$q$, $q$Approval workflows, QA, rollback, and controlled releases for managing guidance content at scale.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Multi-platform coverage$q$, $q$Guidance and support across web apps, desktop software (Windows and Mac), and mobile apps via SDK.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$AI-powered in-app wiki$q$, $q$Contextual help content with AI-generated summaries surfaced directly inside the application.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Enterprise integrations and SSO$q$, $q$Supports SSO, IP whitelisting, data residency, and integrations with enterprise systems.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Self-service support deflection$q$, $q$In-app guidance and search reduce reliance on help-desk tickets by answering questions in context.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Deep, mature feature set across guidance, training, and analytics$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Strong enterprise governance for managing content at scale$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Covers web, desktop, and mobile in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Backed by significant funding and a large, established customer base$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$AI-assisted authoring speeds up content creation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$No public pricing makes budgeting difficult upfront$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Primarily built for large enterprises, which can be overkill for small teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Implementation and content maintenance require dedicated internal ownership$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Full feature set is split across several separate product modules$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$What does Whatfix do$q$, $q$Whatfix is a digital adoption platform that adds in-app guidance, simulated training, and analytics on top of existing software so users can learn it without leaving their workflow.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$How much does Whatfix cost$q$, $q$Whatfix does not publish fixed pricing. Costs are quoted based on the applications covered, modules selected, and number of user licenses, combining a flat fee with per-user charges.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Who founded Whatfix$q$, $q$Whatfix was co-founded in 2014 by Khadim Batti, who is CEO, and Vara Kumar.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Where is Whatfix based$q$, $q$Whatfix is headquartered in both San Jose, California and Bengaluru, India.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$What is Whatfix Mirror$q$, $q$Mirror is Whatfix's tool for capturing screen recordings of real workflows and turning them into guided simulations and training content, including SCORM exports.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Does Whatfix work on desktop applications$q$, $q$Yes, Whatfix offers an Operating System layer that provides in-app guidance and support for Windows and Mac desktop applications.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$What is Whatfix Product Analytics$q$, $q$It is a companion module that tracks user action tags, funnels, trends, and user journeys to show where employees or customers experience friction.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Who are Whatfix's main competitors$q$, $q$Whatfix competes primarily with other digital adoption platforms such as WalkMe and Pendo.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Employee software onboarding$q$, $q$Guide new hires through complex internal tools like CRM, ERP, or HR systems with in-app walkthroughs rather than static training documents.$q$, $q$Enterprise HR and IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Customer-facing product onboarding$q$, $q$Reduce time-to-value for SaaS customers by embedding contextual guidance directly inside the product.$q$, $q$SaaS customer success and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Support ticket deflection$q$, $q$Surface in-app self-service content and search so users resolve common questions without contacting the help desk.$q$, $q$Enterprise support and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Standard$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["In-app guidance (task lists, tips, flows, beacons, pop-ups)","Manual language translation","Guidance analytics","Limited integrations","SSO and IP whitelisting","24/5 support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Premium$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["Everything in Standard","Custom surveys","Unlimited content aggregation","Auto translation and auto testing","Full integration support","Offline and virtual desktop support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$Enterprise$q$, $q$Custom quote$q$, $q$Annual contract$q$, NULL, $q$["Multi-app or unlimited DAP implementations","All Premium capabilities","Named success manager","Optional white-label and on-premise authoring add-ons"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$overview$q$, $q$What Is Whatfix$q$, 2, ARRAY[$q$Whatfix is an enterprise digital adoption platform that overlays contextual, in-app guidance, simulated training, and usage analytics on top of web, desktop, and mobile applications.$q$, $q$Founded in 2014 by Khadim Batti and Vara Kumar, the company is headquartered in both San Jose, California and Bengaluru, India, and has grown into one of the larger vendors in the digital adoption category, backed by significant venture funding.$q$, $q$The platform is designed for large organizations that need employees and customers to learn complex software quickly, whether that is an internal ERP system, a CRM, or a customer-facing SaaS product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Whatfix's core Digital Adoption Platform provides a no-code editor and AI-assisted authoring for building task lists, smart tips, flows, beacons, pop-ups, and launchers directly inside any application.$q$, $q$Enterprise governance tools support content approval workflows, QA, rollback, and controlled release management, so guidance content can be maintained safely across many applications at scale.$q$, $q$Beyond the core DAP, Whatfix offers a mobile SDK, an Operating System layer for desktop guidance, and Mirror, a screen-recording tool that converts real workflows into simulations and SCORM-exportable training content, complemented by a Product Analytics module for funnel, trend, and user-journey insights.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('4fb71d52-71a3-4323-95eb-7716ce97e45c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Whatfix does not publish fixed public pricing. Instead, it quotes deployments individually based on the applications covered, the modules selected, and the number of user licenses.$q$, $q$The published tier structure includes Standard, Premium, and Enterprise plans across its Digital Adoption Platform, Product Analytics, Mobile, and Mirror products, with Enterprise plans supporting multi-app or unlimited implementations.$q$, $q$The overall pricing model combines a flat platform fee tied to the chosen product and plan with additional per-user license fees, and optional add-ons such as white-labeling, on-premise authoring, and 24/7 support are quoted separately.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Drag-and-drop scheduling$q$, $q$Build fixed or rotating shift schedules across multiple weeks and locations from one interface.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Mobile time clock with geofencing$q$, $q$Employees clock in and out from mobile devices or kiosks, with geofencing to help confirm they are on-site.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Shift swapping and OpenShifts$q$, $q$Employees can request time off, swap shifts, and claim open shifts directly in the app.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Team messaging$q$, $q$Built-in messaging lets managers broadcast schedule changes or message staff without a separate app.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Schedule templates and forecasting$q$, $q$Reusable templates and labor forecast tools speed up recurring schedule creation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Payroll and POS integrations$q$, $q$Connects with Gusto, Paychex Flex, ADP Workforce Now, QuickBooks Online, and other systems.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Role-based permissions$q$, $q$Pro and Premium plans support advanced scheduling rules and role-based access control.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$API and SSO access$q$, $q$Premium plan adds API key access, webhooks, and SAML/SSO for enterprise identity management.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Affordable per-user pricing with no long-term contract$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Mobile-first design suited to frontline, shift-based employees$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Combines scheduling, time tracking, and messaging in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Broad set of payroll and POS integrations$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$14-day free trial with no credit card required$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Advanced features like API access and SSO are limited to the top Premium tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Geared toward hourly, shift-based teams rather than salaried project work$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Reporting and forecasting depth increases significantly only on paid tiers above Essentials$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Some integrations require add-on configuration$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$How much does When I Work cost$q$, $q$Plans are billed per user per month: Essentials starts at 2.50 dollars, Pro is 5 dollars, and Premium is 8 dollars per user per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Is there a free trial$q$, $q$Yes, When I Work offers a 14-day free trial with full feature access and no credit card required.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Who founded When I Work$q$, $q$Chad Halvorson founded the company in 2010 in Minneapolis, Minnesota, where it remains headquartered.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Does When I Work include time tracking$q$, $q$Yes, time and attendance tracking with mobile and kiosk clock-in and geofencing can be toggled on or off across all plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$What integrations does When I Work support$q$, $q$It integrates with over 20 tools including Google Calendar, Gusto, Paychex Flex, ADP Workforce Now, QuickBooks Online, and Slack.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Can employees swap shifts themselves$q$, $q$Yes, employees can request time off and swap or claim OpenShifts directly in the mobile app without manager intervention for each change.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Does When I Work support multiple locations$q$, $q$Yes, multi-location scheduling is included starting with the Essentials plan.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$What businesses use When I Work$q$, $q$It is designed for hourly and shift-based industries such as retail, hospitality, healthcare, and food service.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Multi-location retail scheduling$q$, $q$Retail chains can build and manage recurring shift schedules across several store locations from one account.$q$, $q$Retail operations managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Restaurant and hospitality shift management$q$, $q$Managers can quickly fill shifts, handle last-minute swaps, and track hourly attendance for frontline staff.$q$, $q$Restaurant and hospitality managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Healthcare and field team coordination$q$, $q$Organizations with rotating or on-call shifts can forecast labor needs and keep staff informed via in-app messaging.$q$, $q$Healthcare administrators and field service managers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Essentials$q$, $q$$2.50$q$, $q$per user per month$q$, NULL, $q$["Unlimited users","Auto scheduling","Multi-week and multi-location scheduling","Schedule templates and forecast tools","In-app team messaging","OpenShifts and shift swapping","Payroll and POS integrations"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Pro$q$, $q$$5$q$, $q$per user per month$q$, NULL, $q$["Everything in Essentials","Advanced scheduling rules","Role permissions","Labor sharing","Custom unit forecasting","Custom reporting","Time zone toggling"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$Premium$q$, $q$$8$q$, $q$per user per month$q$, NULL, $q$["Everything in Pro","API key access","Webhooks","SAML/SSO"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$overview$q$, $q$What Is When I Work$q$, 2, ARRAY[$q$When I Work is a scheduling and workforce management app built for hourly and shift-based businesses. It combines shift scheduling, time and attendance tracking, and team messaging into a single mobile-first platform.$q$, $q$Founded in 2010 by Chad Halvorson in Minneapolis, the company built the product to replace manual, spreadsheet-driven scheduling with a system where managers can build recurring schedules quickly and employees can manage their own availability.$q$, $q$The platform reports over 200,000 workplaces and roughly one million users worldwide, spanning industries like retail, hospitality, healthcare, and food service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Scheduling is built around a drag-and-drop interface supporting fixed and rotating shifts, multi-week planning, multi-location scheduling, and reusable templates, backed by forecast tools for planning labor needs.$q$, $q$Employees use the mobile app to view schedules, submit availability, request time off, and manage shift swaps and OpenShifts, reducing back-and-forth with managers.$q$, $q$A time and attendance module supports mobile and kiosk clock-in with geofencing, and built-in team messaging lets managers communicate shift changes directly inside the app rather than through separate texting tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1e8b0c5f-bbcf-4d83-aace-f29444c38a5d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$When I Work offers three per-user, per-month plans: Essentials at 2.50 dollars, Pro at 5 dollars, and Premium at 8 dollars, each billed per user with no long-term contract required.$q$, $q$Essentials covers core scheduling, messaging, OpenShifts, and payroll or POS integrations. Pro adds advanced scheduling rules, role permissions, and custom reporting, while Premium adds API access, webhooks, and SAML/SSO for larger organizations.$q$, $q$A 14-day free trial with full feature access is available without a credit card, and customers can adjust seat counts or cancel at any time.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$No-download browser meetings$q$, $q$Guests join video calls directly from a link in their browser with no app install required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Permanent custom room links$q$, $q$Reusable meeting room URLs that do not expire, useful for recurring client or team meetings.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Screen sharing and whiteboard$q$, $q$Built-in screen sharing and a virtual whiteboard support collaborative calls.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Breakout and co-location groups$q$, $q$Split larger meetings into breakout groups or support hybrid meetings with co-location groups.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Recording$q$, $q$Record meetings, with unlimited recording available on paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Custom branding$q$, $q$Paid plans support custom branding and a custom subdomain for a white-labeled meeting experience.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Whereby Embedded API and SDK$q$, $q$Developers can programmatically create and customize video rooms to embed calling inside their own applications.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Background effects$q$, $q$Blur or replace video backgrounds directly in the browser without extra software.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$No downloads needed for guests to join a call$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Simple, permanent meeting links are easy to reuse and share$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Embedded API lets developers add video calling to their own products$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Clean, lightweight interface compared to heavier conferencing suites$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Free plan available for casual or low-volume use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Free plan is limited to four attendees and 30-minute sessions$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Fewer enterprise-grade admin and compliance features than Zoom or Microsoft Teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Larger meeting capacity requires upgrading to higher-priced plans$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Embedded product requires developer resources to integrate$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Do guests need to download an app to join a Whereby call$q$, $q$No, Whereby is browser-based, so guests can join a meeting directly from a link without installing software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Is Whereby free$q$, $q$Yes, Whereby offers a Free plan limited to one meeting room, four attendees, and 30-minute sessions, with paid plans removing those limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$What is the difference between Whereby Meetings and Whereby Embedded$q$, $q$Meetings is the standalone video calling product for individuals and teams, while Embedded is an API and SDK for developers to add video calling into their own applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Was Whereby previously called something else$q$, $q$Yes, Whereby was originally launched as appear.in in 2013 and was rebranded to Whereby in 2019.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Where is Whereby based$q$, $q$Whereby traces its roots to Oslo, Norway, and operates as a largely remote, distributed organization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$How many people can join a Whereby meeting$q$, $q$Capacity depends on the plan, with higher-tier plans supporting significantly more participants than the Free plan's four-person limit.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Can I record meetings in Whereby$q$, $q$Yes, recording is available, with unlimited recording included on paid plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Does Whereby support custom branding$q$, $q$Yes, paid plans allow custom branding and a custom subdomain for meeting links.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Client-facing consultations$q$, $q$Businesses can send clients a simple meeting link for calls without requiring them to install any software.$q$, $q$Consultants, agencies, and client-facing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Recruiting interviews$q$, $q$Recruiters can use permanent room links for candidate interviews with minimal setup friction for external participants.$q$, $q$HR and talent acquisition teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Embedded video for SaaS products$q$, $q$Developers can use Whereby Embedded to add video calling features directly inside their own platforms.$q$, $q$Product and engineering teams building video-enabled apps$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 meeting room","Up to 4 attendees","30-minute session limit","Basic screen sharing","Background effects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Pro$q$, $q$From around $8.99$q$, $q$per user per month$q$, NULL, $q$["Unlimited meeting duration","Multiple room URLs","Unlimited recording","Custom branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Business$q$, $q$From around $11.99$q$, $q$per host per month$q$, NULL, $q$["Unlimited shared rooms","Custom subdomain","Larger meeting capacity (up to around 200 participants)","Priority support and early feature access"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$Build (Embedded)$q$, $q$Usage-based$q$, $q$per usage$q$, NULL, $q$["API and SDK access","Programmatic room creation","Extensive customization for embedding video into products"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$overview$q$, $q$What Is Whereby$q$, 2, ARRAY[$q$Whereby is a browser-based video conferencing tool that lets people join calls directly from a link, without downloading an app or creating an account as a guest.$q$, $q$The product started life as appear.in, launched in 2013 as an intern project inside Norwegian telecom Telenor in Oslo, and was one of the first web apps built on the WebRTC standard. It spun out with new ownership in 2017 and was rebranded to Whereby in 2019.$q$, $q$Whereby now offers two product lines: Whereby Meetings for individuals and teams who want simple, no-download video calls, and Whereby Embedded for developers who want to add video calling directly into their own applications.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Whereby Meetings offers permanent, custom room links, screen sharing, background effects, breakout groups, co-location groups for hybrid setups, recording, and a virtual whiteboard, all directly in the browser.$q$, $q$Whereby Embedded provides an API and SDK for developers to create meeting rooms programmatically and customize the video experience for their own products, billed based on usage rather than per seat.$q$, $q$Because it is browser-first, Whereby is often used for meetings involving external guests, such as client calls or interviews, where asking someone to install dedicated software would create friction.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5a9eace0-9ae6-46ca-a41f-e970f5f11aea', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Whereby offers a Free plan limited to one meeting room, up to four attendees, and 30-minute session limits, along with basic screen sharing and background effects.$q$, $q$Paid Meetings plans remove the session time limit and add features like more room URLs, unlimited recording, custom branding, larger participant capacity, and priority support, generally priced per user per month.$q$, $q$Whereby Embedded is billed separately on a usage basis, since it is aimed at developers embedding video calling into their own products rather than individual meeting hosts.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Citation Finder$q$, $q$Discovers competitor citations across local directories to guide citation-building efforts.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Rank Tracker$q$, $q$Tracks local and map-pack keyword rankings across mobile and desktop.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Ranking Grids$q$, $q$Visualizes rankings across up to 225 geographic grid points around a business location.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Google Business Profile management (Local Platform)$q$, $q$Bulk-edit listings across locations and prevent unwanted third-party changes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Reputation Builder$q$, $q$Automates review generation and monitoring across multiple business locations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Listings Service$q$, $q$Done-for-you citation building and cleanup across major directories.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Yext Replacement Service$q$, $q$Helps businesses migrate their listings away from Yext's subscription model.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Done-for-you SEO services$q$, $q$Full-service local SEO management and audits for businesses that want an agency to handle the work.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Long-established specialist focus specifically on local SEO$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Modular pricing lets customers pay only for the tools they need$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Ranking Grids provide granular geographic visibility other tools lack$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Combines self-serve software with optional done-for-you services$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Strong reputation for citation data quality and research$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Modular pricing across many separate products can be confusing to budget for$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Some tools are priced separately rather than bundled into one plan$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Primarily focused on local SEO, so it does not cover broader technical or content SEO$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Higher-volume plans and multi-location pricing can get expensive$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$What does Whitespark do$q$, $q$Whitespark provides local SEO software and services, including citation building, Google Business Profile management, local rank tracking, and review management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$How much does Whitespark cost$q$, $q$Pricing is modular by product, starting at 1 dollar per month per location for the Local Platform, with other tools ranging from about 10 to 200 dollars per month depending on features and volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Who founded Whitespark$q$, $q$Whitespark was founded by Darren Shaw in 2005 and is headquartered in Edmonton, Alberta, Canada.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$What is the Local Citation Finder$q$, $q$It is a tool that identifies where competitors have local business citations so users can build matching listings to improve local search relevance.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Does Whitespark offer done-for-you services$q$, $q$Yes, including a Listings Service for citation building and cleanup, a Yext Replacement Service, and broader managed local SEO services.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$What are Local Ranking Grids$q$, $q$A tool that tracks keyword rankings across up to 225 geographic points around a business to show exactly where visibility is strong or weak.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Is there a free trial for Whitespark$q$, $q$Whitespark offers a free trial and some limited free tools for users to test the platform before subscribing.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Who is Whitespark best suited for$q$, $q$Local SEO agencies, multi-location businesses, and franchises that need to manage citations, rankings, and Google Business Profiles at scale.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Multi-location Google Business Profile management$q$, $q$Franchises and multi-location businesses can bulk-manage and protect their Google Business Profile listings from a single dashboard.$q$, $q$Franchise operators and multi-location businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local SEO agency workflows$q$, $q$Agencies can use citation finding, rank tracking, and ranking grids to build and report on local SEO campaigns for clients.$q$, $q$Local SEO agencies and consultants$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Reputation and review management$q$, $q$Businesses can automate review requests and monitoring across locations to build local trust signals.$q$, $q$Multi-location service businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Platform$q$, $q$$1$q$, $q$per month per location$q$, NULL, $q$["Google Business Profile management","Bulk editing across locations","Protection from unwanted listing updates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Ranking Grids$q$, $q$From $10$q$, $q$per month$q$, NULL, $q$["Rankings tracked across up to 225 geographic points","Visual local visibility reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Rank Tracker$q$, $q$$14 to $200$q$, $q$per month$q$, NULL, $q$["Local and map-pack rank tracking","Mobile and desktop tracking"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Local Citation Finder$q$, $q$$33 to $149$q$, $q$per month$q$, NULL, $q$["Competitor citation discovery","Citation monitoring tools"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$Reputation Builder$q$, $q$$79$q$, $q$per month per location$q$, NULL, $q$["Automated review generation","Review monitoring across locations"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$overview$q$, $q$What Is Whitespark$q$, 2, ARRAY[$q$Whitespark is a local SEO software and services company that helps businesses and agencies improve visibility in local search and map results through citation building, Google Business Profile management, and local rank tracking.$q$, $q$Founded by Darren Shaw in 2005 and headquartered in Edmonton, Alberta, Canada, the company shifted its focus specifically to local search marketing around 2010 and has since built a suite of tools known especially for local citation research.$q$, $q$Whitespark combines self-serve software with optional done-for-you services, so customers can either manage local SEO themselves or hand the work off to Whitespark's team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The Local Citation Finder identifies where competitors are listed across local directories and aggregators, helping businesses build matching citations that strengthen local search relevance.$q$, $q$The Local Rank Tracker and Local Ranking Grids monitor keyword and map-pack rankings across mobile and desktop, with Ranking Grids tracking up to 225 geographic points to visualize exactly where visibility is strong or weak.$q$, $q$The Local Platform manages Google Business Profiles in bulk across locations and guards against unwanted third-party updates, while Reputation Builder automates review generation and monitoring for multi-location businesses.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ab7eacb8-b8b0-4ec2-9930-7d165f43051c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Whitespark uses modular, per-product pricing rather than one bundled plan. The Local Platform starts at 1 dollar per month per location, and other tools like the Local Rank Tracker, Local Citation Finder, and Local Ranking Grids scale from roughly 10 to 200 dollars per month depending on volume.$q$, $q$Reputation Builder is priced at about 79 dollars per month per location, with custom pricing for multi-location deployments.$q$, $q$Done-for-you services are priced separately: the Listings Service ranges from 20 to 999 dollars as a one-time fee, the Yext Replacement Service is 399 dollars per location one-time, and full-service SEO packages range from about 499 to 1,999 dollars per month.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Mobile event app$q$, $q$Attendee-facing app with personalized agendas, profiles, and networking tools for conferences and trade shows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$In-app messaging and community board$q$, $q$Attendees can message each other and participate in a shared community discussion board.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Live polling and Q&A$q$, $q$Real-time audience engagement tools for sessions and keynotes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Contact exchange for networking$q$, $q$Digital contact-exchange feature that helps attendees connect and follow up after sessions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Online registration management$q$, $q$Comprehensive tools for handling event registration and ticketing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Virtual exhibitor booths and lead generation$q$, $q$Sponsor and exhibitor tools for showcasing products and capturing leads during the event.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Event badge generation$q$, $q$Automated badge creation for in-person check-in.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Virtual and hybrid event support$q$, $q$Tools to run sessions for remote attendees alongside or instead of in-person components.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Combines app, registration, and marketing tools in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Strong attendee engagement features like live polling and networking$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Supports in-person, virtual, and hybrid event formats$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Established track record across a large number of events worldwide$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Sponsor and exhibitor tools support monetization for larger events$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$No public pricing makes cost comparison difficult without a sales call$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Per-event pricing can add up for organizations running frequent events$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Feature depth is geared toward conferences and trade shows rather than smaller meetups$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Requires a demo or quote request to get exact costs$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$What is Whova used for$q$, $q$Whova is used to manage conferences, trade shows, and similar events, covering registration, a mobile attendee app, marketing, and virtual or hybrid event delivery.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$How much does Whova cost$q$, $q$Whova charges a per-event fee based on factors like attendance size and selected modules, and it does not publish fixed public pricing; customers request a custom quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$When was Whova founded$q$, $q$Whova was founded in 2013 and is headquartered in San Diego, California.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Does Whova support virtual events$q$, $q$Yes, Whova supports virtual and hybrid event formats in addition to in-person events.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Can sponsors and exhibitors use Whova$q$, $q$Yes, Whova offers virtual exhibitor booths and lead-generation tools for sponsors and exhibitors.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Does Whova help with event registration$q$, $q$Yes, Whova includes comprehensive online registration management as part of its event management tools.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Does Whova have networking features$q$, $q$Yes, including attendee profiles, in-app messaging, a community board, and a contact-exchange feature.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$How many events use Whova$q$, $q$Whova states it has served more than 50,000 events across over 170 countries.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$In-person conference management$q$, $q$Event organizers can run registration, badging, and attendee engagement through one app for multi-day conferences.$q$, $q$Conference and association event planners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Trade show exhibitor engagement$q$, $q$Organizers can offer sponsors and exhibitors virtual booths and lead-generation tools to capture attendee interest.$q$, $q$Trade show organizers and sponsors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Hybrid and virtual event delivery$q$, $q$Organizations can extend an event to remote attendees with virtual session delivery alongside in-person components.$q$, $q$Corporate and association event teams running hybrid events$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$Custom Event Quote$q$, $q$Custom quote$q$, $q$Per event$q$, NULL, $q$["Mobile event app","Online registration","Event marketing tools","Attendee networking and engagement features","Optional virtual/hybrid event add-ons","Sponsor and exhibitor tools"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$overview$q$, $q$What Is Whova$q$, 2, ARRAY[$q$Whova is an all-in-one event management platform built around a mobile event app, online registration, event marketing tools, and virtual and hybrid event support for conferences, trade shows, and similar gatherings.$q$, $q$Founded in 2013 and headquartered in San Diego, California, Whova has grown to serve more than 50,000 events across over 170 countries, spanning small professional meetings to large multi-day conferences.$q$, $q$The platform is designed to cover the full event lifecycle, from registration and marketing before the event to attendee engagement and analytics during and after it.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The attendee-facing event app gives participants a personalized agenda, attendee profiles, in-app messaging, a community board, and a contact-exchange feature for digital networking, along with live polling, Q&A, and a real-time social wall.$q$, $q$Organizer tools include comprehensive registration management, customizable branding, event badge generation, and real-time analytics on attendance and engagement.$q$, $q$Sponsors and exhibitors get virtual exhibitor booths and lead-generation tools, and the platform supports virtual and hybrid formats so organizers can extend an event to remote attendees.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c5bc7207-b92e-4b19-96fd-fdb155854d9f', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Whova does not publish fixed public pricing. Instead, it charges a per-event fee that depends on factors like expected attendance, event duration, and which modules are selected.$q$, $q$Prospective customers typically request a custom price quote or book a demo through Whova's sales team to get pricing scoped to their specific event.$q$, $q$Because pricing scales with event size and complexity, costs can range widely between a small single-day meeting and a large multi-day conference with virtual or hybrid components.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Multiple editing modes$q$, $q$Write content in Markdown, a visual WYSIWYG editor, or raw HTML depending on contributor preference.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Extensive authentication support$q$, $q$Built-in local login plus third-party and enterprise SSO options including LDAP, SAML, Okta, and Azure AD.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Bidirectional Git sync$q$, $q$Sync wiki content with GitHub, GitLab, Bitbucket, or any Git remote for version control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Granular page permissions$q$, $q$Group-based, page-level access control for restricting content to relevant teams.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Flexible full-text search$q$, $q$Built-in search engine with optional Elasticsearch or Algolia integration for larger installs.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Multi-database support$q$, $q$Runs on MariaDB, PostgreSQL, MySQL, SQLite, or MS-SQL Server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Flexible deployment options$q$, $q$Deploy via VM, Docker, Kubernetes, or prebuilt cloud images from providers like DigitalOcean and AWS.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Self-hosted data ownership$q$, $q$Organizations retain full control of their documentation and content, with no vendor lock-in.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Completely free and open source with no feature paywalls$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Strong enterprise-grade authentication and SSO support$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Git sync enables version-controlled documentation workflows$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Flexible database and deployment options$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Multiple editing modes suit different types of contributors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Requires self-hosting knowledge or infrastructure to deploy$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$No official managed hosting or paid support plan from the core project$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Community-driven support rather than dedicated enterprise SLAs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Initial setup and configuration take more effort than a hosted SaaS wiki$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Is Wiki.js free$q$, $q$Yes, Wiki.js is free and open source under the MIT license, with no official paid tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Who created Wiki.js$q$, $q$Wiki.js was created by developer Nicolas Giard under the Requarks project, with its first public release in 2016.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$What databases does Wiki.js support$q$, $q$Wiki.js supports MariaDB, PostgreSQL, MySQL, SQLite, and MS-SQL Server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Can Wiki.js sync with Git$q$, $q$Yes, it supports bidirectional Git sync with GitHub, GitLab, Bitbucket, or any Git remote.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Does Wiki.js support single sign-on$q$, $q$Yes, it supports enterprise authentication including LDAP, SAML, CAS, Auth0, Okta, Azure AD, and generic OAuth2/OpenID Connect.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$How do I deploy Wiki.js$q$, $q$It can be deployed via virtual machine, Docker, Kubernetes, or prebuilt cloud images from providers like DigitalOcean and AWS.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$What editing modes does Wiki.js offer$q$, $q$Markdown, a visual WYSIWYG editor, and raw HTML editing modes are all supported.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Is there a hosted version of Wiki.js$q$, $q$The core project is self-hosted; third-party providers offer managed hosting separately, but there is no official Wiki.js-run SaaS plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Engineering team documentation$q$, $q$Engineering teams can self-host Wiki.js with Git sync to version-control internal documentation alongside their codebase.$q$, $q$Software engineering and DevOps teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Open-source project knowledge base$q$, $q$Open-source projects can run a free, community-editable wiki for documentation without subscription costs.$q$, $q$Open-source maintainers and communities$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Enterprise intranet documentation$q$, $q$Organizations needing SSO-integrated internal documentation can deploy Wiki.js with LDAP, SAML, or Azure AD authentication.$q$, $q$IT and internal knowledge management teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Markdown, WYSIWYG, and HTML editing","Bidirectional Git sync","Enterprise authentication (LDAP, SAML, Okta, Azure AD)","Granular page permissions","Full-text search with Elasticsearch/Algolia options","Multi-database support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$overview$q$, $q$What Is Wiki.js$q$, 2, ARRAY[$q$Wiki.js is a free, open-source wiki engine built on Node.js, created by developer Nicolas Giard and first released publicly in 2016 under the Requarks project.$q$, $q$It is licensed under MIT, meaning the source code is fully open for self-hosting or modification, with no official paid tier from the project itself.$q$, $q$Wiki.js is commonly positioned as a modern, self-hosted alternative to older wiki software like MediaWiki, and to hosted documentation tools like Confluence or Notion, for teams that want to own their infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Wiki.js supports multiple editing modes, including Markdown, a visual WYSIWYG editor, and raw HTML, so different contributors can work the way they prefer.$q$, $q$Authentication is extensive, with built-in local login plus support for Google, Facebook, Microsoft, GitHub, Discord, and Slack, and enterprise systems including LDAP, SAML, CAS, Auth0, Okta, Azure AD, and generic OAuth2/OpenID Connect.$q$, $q$Collaboration features include bidirectional Git sync with GitHub, GitLab, or Bitbucket, granular page-level permissions with group-based rules, and full-text search with optional Elasticsearch or Algolia integration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wiki.js is completely free and open source under the MIT license, with no official paid plan or feature paywall.$q$, $q$It supports MariaDB, PostgreSQL, MySQL, SQLite, and MS-SQL Server as backend databases, and can be deployed via VM, Docker, Kubernetes, or prebuilt cloud images from providers like DigitalOcean and AWS.$q$, $q$Since it is self-hosted, the only ongoing cost is typically server or hosting infrastructure, which organizations control directly rather than paying a SaaS subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b8287b9b-43ca-4726-b309-28a1246e0832', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$IMAP4rev1 with modern extensions$q$, $q$Supports IDLE, CONDSTORE, COMPRESS, SPECIAL-USE, UTF8, and QUOTA for full-featured mailbox access.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$MongoDB-backed storage$q$, $q$Stores accounts, mailboxes, and messages in MongoDB rather than the filesystem, enabling sharding and horizontal scale.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Stateless, horizontally scalable instances$q$, $q$Multiple wildduck instances can run behind a load balancer to handle growing account volume.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$REST API management$q$, $q$Manage accounts, mailboxes, messages, filters, auto-replies, and DKIM keys entirely through an API.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Internationalized email support$q$, $q$Full support for internationalized addresses, folder names, and message headers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Application-specific passwords and MFA$q$, $q$Security features for issuing scoped app passwords and enforcing multi-factor authentication.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$No root privileges required$q$, $q$Runs without root access and does not touch the filesystem for mail storage, reducing attack surface.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Composable mail stack$q$, $q$Pairs with Haraka for inbound SMTP and ZoneMTA for outbound SMTP as part of the Zone Mail Suite.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Free and fully open source under EUPL 1.2$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Built for horizontal scaling to large mailbox counts$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Comprehensive REST API for programmatic mailbox management$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Strong protocol support, including internationalized email$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Does not require root privileges, reducing operational risk$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Requires MongoDB expertise and infrastructure, unlike simpler file-based mail servers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Does not include SMTP handling on its own, requiring additional components like Haraka and ZoneMTA$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Best suited for larger deployments, so it may be overkill for small personal mail setups$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$No official managed hosting or paid support option$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$What is wildduck$q$, $q$wildduck is an open-source IMAP and POP3 email server built on Node.js and MongoDB, designed for scalable, API-driven mail hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Is wildduck free$q$, $q$Yes, wildduck is free and open source under the EUPL 1.2 license, with no official paid tier.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Does wildduck handle SMTP$q$, $q$No, wildduck focuses on IMAP and POP3 mailbox access; it is typically paired with Haraka for inbound and ZoneMTA for outbound SMTP.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$How does wildduck store mail data$q$, $q$It stores accounts, mailboxes, and messages in MongoDB rather than on the filesystem, which supports sharding and horizontal scaling.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Who created wildduck$q$, $q$wildduck was created by developer Andris Reinman, based in Tallinn, Estonia, as part of the Zone Mail Suite.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Is wildduck suitable for small personal mail servers$q$, $q$It is explicitly designed for larger deployments of 1,000 or more mailboxes; smaller setups may be better served by simpler mail servers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Can wildduck be managed via API$q$, $q$Yes, all management, including accounts, mailboxes, filters, and DKIM keys, is handled through a REST API.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Does wildduck support multi-factor authentication$q$, $q$Yes, it supports application-specific passwords and multi-factor authentication.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Large-scale mail hosting providers$q$, $q$Hosting providers can use wildduck to programmatically provision and scale thousands of mailboxes via its REST API.$q$, $q$Email hosting providers and infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Self-hosted enterprise email$q$, $q$Organizations wanting full control of their email infrastructure can self-host wildduck alongside Haraka and ZoneMTA for a complete mail stack.$q$, $q$Enterprise IT and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$SaaS products embedding mailbox features$q$, $q$Developers building products that need managed mailbox infrastructure can integrate wildduck's REST API rather than building IMAP support from scratch.$q$, $q$Developers building email-dependent SaaS products$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$Self-Hosted$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full IMAP4rev1 and POP3 support","MongoDB-backed, sharding-ready storage","REST API for accounts, mailboxes, and messages","Application-specific passwords and MFA","Composable with Haraka and ZoneMTA for full mail stack"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$overview$q$, $q$What Is wildduck$q$, 2, ARRAY[$q$wildduck is an open-source IMAP and POP3 email server built on Node.js and MongoDB, created by developer Andris Reinman and released as part of the Zone Mail Suite under the EUPL 1.2 license.$q$, $q$Unlike traditional mail servers that store mailboxes on the filesystem, wildduck stores every account, mailbox, and message in MongoDB, which allows it to scale horizontally across sharded database clusters.$q$, $q$It is explicitly designed for larger deployments, targeting organizations managing 1,000 or more mailboxes that need to scale beyond a single server, and is commonly paired with Haraka and ZoneMTA to form a complete inbound and outbound mail server stack.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$wildduck provides a first-class IMAP4rev1 implementation with IDLE, CONDSTORE, COMPRESS, SPECIAL-USE, UTF8, and QUOTA support, along with full support for internationalized addresses, folder names, and headers.$q$, $q$Because every instance is stateless, administrators can run multiple wildduck instances behind a load balancer to increase throughput as mailbox volume grows, rather than scaling a single monolithic server.$q$, $q$The entire server is managed through a REST API covering accounts, mailboxes, messages, filters, auto-replies, and DKIM keys, and it supports application-specific passwords and multi-factor authentication without requiring root privileges.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$wildduck is free, open-source software licensed under the EUPL 1.2, with no official paid tier or license fee.$q$, $q$Since it is self-hosted, organizations only bear their own infrastructure costs, including servers and MongoDB hosting, rather than paying a subscription to a vendor.$q$, $q$There is no managed wildduck-as-a-service offering from the core project; deployment and scaling are handled by the organization running it.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('591b7aee-2302-4201-805a-465e25e4cfbc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
