-- Enrichment marathon batch: wger, Whatfix, When I Work, Whereby, Whitespark, Whova, Wiki.js, wildduck

-- ── wger ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$wger is a free, open-source, self-hosted fitness platform for planning workout routines, tracking nutrition, and logging body measurements and progress photos.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$]::text[],
  seo_title = COALESCE($q$wger Review 2026: Free Open-Source Workout and Nutrition Manager$q$, seo_title),
  seo_meta_description = COALESCE($q$wger is a free, open-source fitness manager for workout routines, nutrition tracking, and progress logging. See features, self-hosting options, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$wger (Workout GEneratoR) is a free and open-source fitness and workout management application originally built by developer Roland Geider and shared publicly in 2014. It is licensed under the GNU Affero General Public License (AGPL-3.0 or later), meaning the full source code is available and anyone can self-host, modify, or contribute to it, and there is no company or paid tier behind the core software. The project is maintained by the wger-project organization on GitHub with contributions from a broad community of developers and translators. wger covers three main areas of personal fitness tracking: workout planning, nutrition logging, and body progress monitoring. Users can build weekly training routines from a library of more than 100 exercises, each configurable with sets, reps, weight, duration, or distance targets, and the software supports automatic weight progression rules so routines adapt over time. For nutrition, wger connects to the Open Food Facts database, giving access to a food catalog of several million items, and automatically calculates energy, protein, carbohydrate, and fat totals for logged meals. Users can also track body weight, custom measurements, and upload progress photos to visualize change over time. A REST API is available for building integrations or automations on top of the platform, and wger includes basic multi-user and gym-management functionality, making it usable by individual trainees as well as small gyms or trainers managing several clients. wger is cross-platform: it ships official Android and iOS mobile apps (the Android app dates to 2020, the iOS app to 2024), and the Android build is also distributed through F-Droid and Flathub for users who prefer open-source app stores. Because it is self-hosted, deployment is typically done via Docker, giving administrators full control over their data, with no ads and no sale of personal information — a common selling point for people who want to leave closed, subscription-based fitness apps. Third-party managed-hosting providers (such as Elestio) offer wger as a hosted service for people who do not want to run their own server, but this is a separate commercial offering layered on top of the free open-source project rather than an official paid plan from the wger project itself. wger is best understood as a privacy-respecting, community-maintained alternative to commercial fitness-tracking apps like Strong, Hevy, or MyFitnessPal, aimed at users and small gyms who want full ownership of their training and nutrition data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2c05a9b7-fdb5-409f-8a14-64eb71fbdace';

