-- ── Whatfix ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Whatfix is an enterprise digital adoption platform that layers in-app guidance, simulated training, and usage analytics onto web, desktop, and mobile applications to speed up onboarding and cut support tickets.$q$, short_description),
  pricing_model = COALESCE($q$custom$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE($q$1,000+ employees$q$, company_size),
  headquarters = COALESCE($q$San Jose, California and Bengaluru, India$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Whatfix Review 2026: Digital Adoption Platform Features and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Whatfix is an enterprise digital adoption platform for in-app guidance, training, and analytics. See features, plans, and how it compares for onboarding software.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Whatfix is an enterprise digital adoption platform (DAP) co-founded in 2014 by Khadim Batti (CEO) and Vara Kumar, headquartered jointly in San Jose, California and Bengaluru, India. The company has raised over 300 million dollars in venture funding, including a Series E round led by Warburg Pincus and previous backing from SoftBank Vision Fund 2, reaching a reported valuation of roughly 900 million dollars, and employs over a thousand people globally. Whatfix helps organizations overlay contextual, in-app guidance on top of any web, desktop, or mobile software so employees and customers can learn how to use complex applications without leaving the workflow. Its core product line spans four areas: the Digital Adoption Platform for web and desktop apps, a mobile SDK, an Operating System layer for Windows and Mac guidance, and Mirror, a tool for capturing screen recordings and turning them into guided simulations and training content, including SCORM exports for learning management systems. Within the DAP, features include a no-code editor and AI-assisted content authoring, task lists, smart tips, in-app flows, beacons, pop-ups, launchers, and an in-app wiki with AI-generated summaries. Enterprise governance features support content approvals, QA, rollback, and controlled releases, so large organizations can manage guidance content across many applications without breaking existing workflows. A companion Product Analytics module tracks user action tags, funnels, trends, and user journeys to show where employees or customers struggle, and Whatfix pairs this with adoption dashboards for continuous optimization. Common use cases include onboarding new hires and new customers, guiding employees through complex multi-step workflows such as CRM or ERP processes, deflecting help-desk tickets through in-app self-service, reinforcing compliance and process adherence, and supporting software rollouts, migrations, and policy changes. Whatfix competes with other digital adoption platforms such as WalkMe and Pendo, and it is typically deployed by large and mid-market enterprises layering guidance onto systems like Salesforce, Workday, SAP, or custom internal tools. Pricing is fully custom: Whatfix does not publish fixed prices and instead quotes based on the number of applications, modules, and user licenses involved, combining a flat platform fee with per-user licensing, and offering Standard, Premium, and Enterprise tiers plus optional add-ons like white-labeling, on-premise authoring, and dedicated adoption program management.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '4fb71d52-71a3-4323-95eb-7716ce97e45c';

