-- ── When I Work ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$When I Work is an employee scheduling and time-tracking platform that combines shift scheduling, a mobile time clock, and team messaging in one app for shift-based businesses.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$$2.50 per user per month$q$, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Minneapolis, Minnesota, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$When I Work Review 2026: Employee Scheduling Software Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$When I Work is an employee scheduling and time-tracking app for shift-based teams. Compare Essentials, Pro, and Premium pricing, features, and integrations.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$When I Work is an employee scheduling and workforce management platform founded in 2010 by Chad Halvorson in Minneapolis, Minnesota, where the company remains headquartered. It was built to replace manual, spreadsheet-based shift scheduling for hourly and shift-based workplaces, and the company reports more than 200,000 workplaces and roughly one million users across over 50 countries using the platform. The core product centers on a drag-and-drop scheduling interface that supports fixed shifts, rotating shifts, multi-week schedules, and multi-location scheduling from a single account, along with reusable schedule templates and forecast tools for planning labor needs. Employees interact with the platform through a mobile app where they can view their schedule, submit availability, request time off, and initiate or accept shift swaps and OpenShifts (unfilled shifts employees can claim) without needing a manager to manually reassign work. A built-in time and attendance module lets employees clock in and out from mobile devices or physical kiosks, with geofencing to help confirm that clock-ins happen at the correct job site, and this time-tracking functionality can be toggled on or off across plans. Team messaging is built into the app as well, letting managers broadcast shift updates or communicate directly with staff without relying on a separate texting or messaging tool. When I Work integrates with more than 20 third-party systems, including Google Calendar, Gusto, Paychex Flex, ADP Workforce Now, QuickBooks Online, and Slack, which lets scheduling and time data flow into payroll and point-of-sale systems many businesses already use. Pricing is structured in three tiers billed per user per month: Essentials at 2.50 dollars covers unlimited users, auto scheduling, multi-week and multi-location scheduling, schedule templates, forecast tools, in-app messaging, OpenShifts and shift swapping, and payroll or POS integrations; Pro at 5 dollars adds advanced scheduling rules, role permissions, labor sharing, custom unit forecasting, custom reporting, and time zone toggling; and Premium at 8 dollars adds API key access, webhooks, and SAML/SSO for larger organizations that need deeper integration and identity management. All plans include a 14-day free trial with full feature access and no credit card required, and customers can add or remove seats or cancel at any time without long-term contracts. When I Work is best suited for retail, hospitality, healthcare, and other hourly, shift-based businesses that need to build recurring schedules quickly and give frontline staff self-service control over their availability and time off.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1e8b0c5f-bbcf-4d83-aace-f29444c38a5d';

