-- ── Whereby ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Whereby is a browser-based video conferencing tool that lets people join meetings instantly via a link with no downloads, plus an embeddable video API for developers.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free, paid plans from around $8.99 per user per month$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Oslo, Norway$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Whereby Review 2026: Browser-Based Video Conferencing Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Whereby is a no-download, browser-based video calling tool with an embeddable video API. Compare Free, Pro, and Business plans and key features.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Whereby is a browser-based video conferencing platform that originated as appear.in, a project started in 2013 as a summer intern effort inside Norwegian telecom company Telenor in Oslo. It was one of the earliest web applications to use the WebRTC standard, letting people join a video call directly from a browser link with no app download or account required for guests. In 2017 the product spun out with new ownership under Videonor, and in 2019 appear.in was rebranded to Whereby following a trademark dispute over the original name, along with a full UX overhaul of the meeting experience. The company operates as a distributed, largely remote organization with roots in Oslo, Norway. Whereby's product line has two main parts: Whereby Meetings, aimed at individuals and teams who want simple video calls, and Whereby Embedded, aimed at developers and product builders who want to add video calling into their own applications via API and SDK tooling. Meetings features include permanent, custom meeting room links that do not expire between calls, screen sharing, background effects, breakout groups, co-location groups for hybrid meetings, recording, and a virtual whiteboard, all accessible without installing dedicated meeting software. Whereby Embedded gives developers programmatic room creation, extensive customization options, and usage-based billing so companies can white-label video calling inside their own products rather than building WebRTC infrastructure from scratch. On the Meetings side, Whereby offers a Free plan limited to one meeting room, up to four attendees, and 30-minute session caps, alongside basic screen sharing and background effects. Paid Meetings plans (commonly marketed as Pro and Business tiers, with published pricing in roughly the 8 to 12 dollar per user per month range depending on the promotion and billing cycle) remove the time limit, add more room URLs, unlimited recording, custom branding, larger meeting capacity of up to around 200 participants, a custom subdomain, and priority support. Because Whereby is browser-first, it appeals to businesses that want to send external clients or candidates a simple video link without asking them to install software, which distinguishes it from heavier enterprise platforms like Zoom or Microsoft Teams. It is commonly used for client-facing meetings, recruiting interviews, telehealth-style consultations, and lightweight team calls, as well as being embedded directly into other SaaS products through its Embedded API.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5a9eace0-9ae6-46ca-a41f-e970f5f11aea';

