-- ── Whitespark ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Whitespark is a local SEO software and services company providing citation building, Google Business Profile management, local rank tracking, and review management tools.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$$1 per month per location (Local Platform)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Edmonton, Alberta, Canada$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Whitespark Review 2026: Local SEO Citation Tools and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Whitespark offers local SEO software for citation building, Google Business Profile management, and rank tracking. Compare tools, services, and pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Whitespark is a local SEO software and services company founded by Darren Shaw in 2005 and headquartered in Edmonton, Alberta, Canada. The company reoriented its focus specifically toward local search marketing around 2010 and has since become one of the more established, long-running names in local SEO tooling, known especially for pioneering local citation research. Whitespark's offerings split into two categories: self-serve software tools and done-for-you services. On the software side, the Local Citation Finder helps businesses discover where competitors are listed across local directories and data aggregators so they can build matching citations to strengthen local search relevance and trust signals. The Local Rank Tracker monitors keyword rankings specifically in local and map-pack results across mobile and desktop, letting agencies and businesses see how visibility changes by geography. Local Ranking Grids extend this by tracking rankings across up to 225 individual geographic grid points around a business location, which is useful for visualizing exactly where a business ranks well or poorly within its service area. The Local Platform tool focuses on Google Business Profile management, including bulk editing across multiple locations and safeguards against unwanted third-party updates to listing data. Reputation Builder automates review generation and monitoring, helping multi-location businesses collect and manage customer reviews at scale. On the services side, Whitespark offers a Listings Service for citation building and cleanup, a Yext Replacement Service aimed at businesses migrating away from Yext's subscription-based listings model, and broader done-for-you local SEO services and audits for businesses that want an agency to manage the work directly. Pricing is modular rather than a single bundled plan: the Local Platform starts at 1 dollar per month per location, Local Ranking Grids start around 10 dollars per month, the Local Rank Tracker ranges from about 14 to 200 dollars per month depending on tracked keywords and locations, the Local Citation Finder ranges from about 33 to 149 dollars per month, and Reputation Builder is about 79 dollars per month per location. One-time service pricing includes the Listings Service at 20 to 999 dollars and the Yext Replacement Service at 399 dollars per location, while done-for-you SEO services range from roughly 499 to 1,999 dollars per month. Enterprise and multi-location custom pricing is available across most products. Whitespark is best suited for local SEO agencies, multi-location businesses, and franchises that need to manage citations, rankings, and Google Business Profiles at scale, and it is frequently used alongside broader SEO platforms as a specialist local-search toolkit.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ab7eacb8-b8b0-4ec2-9930-7d165f43051c';

