  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Wiki.js Review 2026: Open-Source Self-Hosted Wiki Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Wiki.js is a free, open-source wiki engine for teams, with Markdown editing, Git sync, and self-hosted deployment. See features, editors, and setup options.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wiki.js is a free, open-source wiki engine created by developer Nicolas Giard under the Requarks project, with its first public release (version 1.0) arriving in 2016. It is licensed under the MIT license, meaning the full source code is freely available for anyone to inspect, self-host, or modify, and there is no paid tier from the project itself, though the maintainer accepts community support through channels like Patreon. Built on Node.js, Wiki.js is positioned as a modern, lightweight, self-hosted alternative to older wiki software such as MediaWiki, and it is frequently compared to tools like Confluence or Notion for teams that want to own their documentation infrastructure rather than rely on a hosted SaaS product. The editing experience supports multiple modes: a Markdown editor, a visual WYSIWYG editor, and a raw HTML mode, letting teams choose the workflow that suits different contributors. Authentication is a particular strength: Wiki.js ships with built-in local authentication including self-registration and password recovery, and it supports third-party login through Google, Facebook, Microsoft, GitHub, Discord, and Slack, as well as enterprise identity systems including LDAP, SAML, CAS, Auth0, Okta, and Azure AD, plus generic OAuth2 and OpenID Connect modules. This makes it viable for organizations that need to plug documentation into an existing single sign-on setup. Collaboration features include Git sync, which provides bidirectional synchronization between the wiki and a Git remote such as GitHub, GitLab, or Bitbucket, letting teams version-control their documentation content alongside code. Access control is granular, supporting page-level permissions with group-based rules so different teams can be restricted to relevant sections of the wiki. Search is flexible, with a built-in search engine as well as optional integration with Elasticsearch or Algolia for larger installations. On the database side, Wiki.js supports MariaDB, PostgreSQL, MySQL, SQLite, and MS-SQL Server, giving administrators flexibility in how they run the backend. Deployment options include virtual machines, Docker, Kubernetes, and prebuilt cloud images for providers like DigitalOcean and AWS, and because it is self-hosted, organizations retain full ownership and control of their documentation data. Wiki.js is best suited for engineering teams, open-source projects, and organizations that want a modern, extensible, and fully self-hosted knowledge base without recurring SaaS subscription costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b8287b9b-43ca-4726-b309-28a1246e0832';

