-- ── wildduck ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$wildduck is an open-source, scalable IMAP and POP3 email server built on Node.js and MongoDB, designed for API-driven mail hosting and horizontal scaling.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted)$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Tallinn, Estonia$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$wildduck Review 2026: Open-Source Scalable IMAP Email Server$q$, seo_title),
  seo_meta_description = COALESCE($q$wildduck is a free, open-source IMAP and POP3 email server built for horizontal scaling. See features, architecture, licensing, and self-hosting details.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$wildduck is an open-source email server focused specifically on IMAP and POP3 mailbox access, created by developer Andris Reinman, who is based in Tallinn, Estonia and works as a technical architect at Zone Media. wildduck is part of the Zone Mail Suite (ZMS), a collection of related open-source mail server components, and it is licensed under the European Union Public License (EUPL) 1.2. Architecturally, wildduck is built on Node.js for the application layer and MongoDB for storage, and every mail-related object, including accounts, mailboxes, and messages, is stored in MongoDB with support for sharding. This design choice is deliberate: rather than relying on the traditional filesystem-based mailbox formats used by legacy mail servers, wildduck stores everything in a document database that can scale horizontally, and every wildduck instance is stateless, meaning administrators can run multiple instances behind a load balancer to increase throughput as account volume grows. The project explicitly targets larger deployments, describing itself as best suited for organizations managing 1,000 or more mailboxes that need horizontal scaling rather than the small, single-server setups more common with traditional IMAP servers like Dovecot. On the protocol side, wildduck provides a first-class implementation of IMAP4rev1, including support for IDLE (push-style new mail notifications), CONDSTORE (efficient synchronization of changes), COMPRESS, SPECIAL-USE folder flags, UTF8 support, and QUOTA management, along with full support for internationalized email addresses, folder names, and message headers, which matters for deployments serving non-English-speaking users. wildduck does not handle SMTP directly; instead, it is commonly bundled with Haraka for inbound SMTP and ZoneMTA for outbound SMTP to form a complete mail server stack, with wildduck itself handling the IMAP/POP3 mailbox-access layer. Management is handled entirely through a REST API covering accounts, mailboxes, messages, filters, auto-replies, DKIM key management, and more, which makes wildduck well suited for hosting providers or platforms that want to programmatically provision and manage large numbers of mailboxes rather than administering them by hand. Security features include support for application-specific passwords and multi-factor authentication, and notably, wildduck does not require root privileges and does not touch the underlying filesystem for mail storage, reducing its operational attack surface compared to traditional mail servers. As a fully open-source project, wildduck has no official pricing; it is free to self-host, and organizations bear only their own infrastructure and MongoDB hosting costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '591b7aee-2302-4201-805a-465e25e4cfbc';

